      console.error(`[document-ingestion] chunk ${i} insert failed:`, chunkErr);
    }
  }

  if (insertedChunkIds.length === 0 || rawText.trim().length <= 20) {
    await db
      .update(documents)
      .set({ status: 'complete', processedAt: new Date() })
      .where(eq(documents.id, documentId));
    return outcome;
